// src/components/InteractionForm.js
import React from "react";
import { useSelector } from "react-redux";

function InteractionForm() {
  const form = useSelector((state) => state.form);
  const sentimentEmoji = { positive: "😊", neutral: "😐", negative: "😞" };
  const sentimentClass = form.sentiment ? form.sentiment : "neutral";

  return (
    <div>
      <h2>Log HCP Interaction</h2>

      {["hcp_name","interaction_type","date","time","topics","outcomes","followup"].map((field) => (
        <div className="field-card" key={field}>
          <label>{field.replace("_"," ").toUpperCase()}</label>
          {["topics","outcomes","followup"].includes(field) ? (
            <textarea value={form[field] || ""} readOnly />
          ) : (
            <input value={form[field] || ""} readOnly />
          )}
        </div>
      ))}

      {form.sentiment && (
        <div className={`sentiment ${sentimentClass}`}>
          {sentimentEmoji[form.sentiment]} {form.sentiment}
        </div>
      )}

      {/* Tools Output */}
      {form.tools && Object.keys(form.tools).map((key) => (
        <div className="field-card" key={key}>
          <label>{key.replace("_"," ").toUpperCase()}</label>
          <pre>{JSON.stringify(form.tools[key], null, 2)}</pre>
        </div>
      ))}
    </div>
  );
}

export default InteractionForm;
